import React, { Component } from "react";
import { TabLink, Tabs, TabContent } from "react-tabs-redux";
import {Grid, Paper} from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';

class Testimonials extends Component {
  render() {
   const useStyles = makeStyles((theme) => ({
      root: {
        display: 'flex',
        flexWrap: 'wrap',
        '& > *': {
          margin: theme.spacing(1),
          width: theme.spacing(16),
          height: theme.spacing(16),
        },
      },
    }));

    return (
      <section id="testimonials">
        <div className="text-container">
          <div className="row">
            <Tabs>
              <Grid container direction="row" spacing={1}>
                 <Grid item xs={3}>
                <ul>
                  <li>
                    <TabLink style={{width:"100%"}} to="tab1">Tab1</TabLink> 
                  </li>
                  <li>
                    <TabLink style={{width:"100%"}} to="tab2">Tab2</TabLink>
                  </li>
                  <li>
                    <TabLink style={{width:"100%"}} to="tab3">Tab3</TabLink>
                  </li>
                </ul>
               </Grid>

                <Grid item xs={9}>
                   <ul>
                  <Paper className={useStyles.root}>
                     <TabContent for="tab1">.sdf.</TabContent>
                     <TabContent for="tab2">.sdf..</TabContent>
                     <TabContent for="tab3">sdf...</TabContent>
                  </Paper>
                  </ul>
                </Grid>
              </Grid>
            </Tabs>

            <div className="ten columns flex-container">

            </div>
          </div>
        </div>
      </section>
    );
  }
}

export default Testimonials;
